func solve(weight []int64) int64 {
    left := 0
    count := 0
    deque := []int{}
    for right := 0; right < len(weight); right++ {
        // Maintain deque for current window
        for len(deque) > 0 && weight[right] >= weight[deque[len(deque)-1]] {
            deque = deque[:len(deque)-1]
        }
        deque = append(deque, right)
        // Remove elements from front that are out of the window
        for len(deque) > 0 && deque[0] < left {
            deque = deque[1:]
        }
        // Check if current window is valid
        if len(deque) > 0 && weight[deque[0]] > weight[right] {
            count++
            left = right + 1
            deque = []int{}
        }
    }
    return int64(count)
}
